SELECT fi.item_name, pd.price
FROM food_items fi
JOIN price_data pd ON fi.item_id = pd.item_id;

SELECT DISTINCT city_name
FROM cities
JOIN data_centers ON cities.city_id = data_centers.city_id;

SELECT cities.city_name, food_items.item_name 
FROM cities, food_items 
WHERE food_items.seasonal = 0 AND food_items.origin = 'India';

SELECT item_name, category 
FROM food_items 
ORDER BY category;

SELECT COUNT(*) 
FROM food_items 
WHERE seasonal = 1;
